targets.expr:
clamp_min(clamp_max((
  (
    sum by (feature_category) (
      rate(gitlab_sli_sidekiq_execution_apdex_total{feature_category!="",shard=~"$shard"}[$__interval])
    )
    -
    sum by (feature_category) (
      rate(gitlab_sli_sidekiq_execution_apdex_success_total{feature_category!="",shard=~"$shard"}[$__interval])
    )
  )
  / ignoring (feature_category) group_left()
  (
    sum by () (
      rate(gitlab_sli_sidekiq_execution_apdex_total{feature_category!="",shard=~"$shard"}[$__interval])
    )
  )
) > 0
,1),0)

